<script setup lang="ts">
import type { EnterpriseProfileItem, EnterpriseWorkspaceSummary } from '#/api';

import { computed, shallowRef, watch } from 'vue';
import { IconifyIcon, RotateCw } from '@vben/icons';
import { Alert, Button, Descriptions, DescriptionsItem, Empty, Progress, Spin, Tag } from 'antdv-next';
import { getEnterpriseWorkspaceSummaryApi } from '#/api';
import {
  getMaterialSectionTarget,
  materialSections,
  type MaterialSectionKey,
  type MaterialSectionTarget,
} from '../material-section';
import { createCompanyOverviewIndicators } from '../company-overview-indicators';
import {
  getCompanyOverviewMetricTarget,
  type CompanyOverviewMetricKey,
} from '../company-overview-metrics';
import { getEnterpriseActionTarget } from '../../enterprise-action-target';
import EnterpriseOperationList from '../../components/EnterpriseOperationList.vue';

interface Props { enterprise: EnterpriseProfileItem; }
const props = defineProps<Props>();
const emit = defineEmits<{ openDeclarations: [declarationId?: string]; selectSection: [target: MaterialSectionTarget] }>();
const loading = shallowRef(false); const summary = shallowRef<EnterpriseWorkspaceSummary>(); const errorMessage = shallowRef('');
const profile = computed(() => summary.value?.profile ?? props.enterprise);
const metrics = computed(() => summary.value?.metrics ?? { activeDeclarations: 0, attachmentRecords: 0, completenessRate: 0, completedModules: 0, healthScore: 0, totalModules: 0 });
const companyStatus = computed(() => profile.value.status === 1 ? { color: 'green', label: '正常' } : { color: 'default', label: '停用' });
const profileStatus = computed(() => { const labels: Record<string, { color: string; label: string }> = { approved: { color: 'success', label: '已通过' }, checking: { color: 'processing', label: '审核中' }, completed: { color: 'success', label: '已完成' }, draft: { color: 'default', label: '待完善' }, invalid: { color: 'warning', label: '待补正' }, pending: { color: 'processing', label: '待确认' }, valid: { color: 'success', label: '已通过' } }; return labels[profile.value.profileStatus] ?? { color: 'default', label: profile.value.profileStatus || '待完善' }; });
const profileItems = computed(() => [{ label: '企业名称', value: profile.value.name || '-' }, { label: '统一社会信用代码', value: profile.value.creditCode || '-' }, { label: '企业类型', value: profile.value.enterpriseType || '-' }, { label: '所属行业', value: profile.value.industry || '-' }, { label: '法定代表人', value: profile.value.legalPerson || '-' }, { label: '联系人', value: profile.value.contactName || '-' }, { label: '联系电话', value: profile.value.contactPhone || '-' }, { label: '联系邮箱', value: profile.value.contactEmail || '-' }, { label: '所在地', value: [profile.value.province, profile.value.city, profile.value.district].filter(Boolean).join(' / ') || '-' }, { label: '详细地址', value: profile.value.address || '-' }]);
const completionLabel = computed(() => `${metrics.value.completedModules} / ${metrics.value.totalModules} 个资料模块已完成`);
const highTechIndicators = computed(() => summary.value?.highTechIndicators ?? { financialYears: 0, intellectualPropertyCount: 0, productServiceCount: 0, researchEmployeeCount: 0, researchProjectCount: 0, transformationCount: 0 });
const moduleStats = computed(() => summary.value?.moduleStats ?? []);
const missingFieldLabels: Record<string, string> = { attachment: '缺少附件', record_count: '缺少记录' };
const completionActions = computed(() => moduleStats.value.filter((item) => !item.isCompleted).sort((left, right) => left.score - right.score).slice(0, 6));
const indicatorItems = computed(() => createCompanyOverviewIndicators(highTechIndicators.value));
function getRiskType(level: 'high' | 'low' | 'medium') { return level === 'high' ? 'error' : level === 'medium' ? 'warning' : 'info'; }
function getDeclarationStatus(status: string) { return ({ approved: '已通过', draft: '草稿', preparing: '准备中', rejected: '已退回', reviewing: '审核中', submitted: '已提交' } as Record<string, string>)[status] ?? status; }
function formatDate(value: Date | string | null) { if (!value) return '未设置截止时间'; return new Intl.DateTimeFormat('zh-CN', { dateStyle: 'medium' }).format(new Date(value)); }
function selectSection(section: MaterialSectionKey) { emit('selectSection', { section }); }
function selectMaterialItem(moduleKey: string, tabKey?: string) { emit('selectSection', getMaterialSectionTarget(moduleKey, tabKey) ?? { section: 'company' }); }
function openMetric(key: CompanyOverviewMetricKey) {
  if (key === 'health' || key === 'completeness') {
    const nextAction = completionActions.value[0];
    if (nextAction) {
      selectMaterialItem(nextAction.moduleKey, nextAction.tabKey);
      return;
    }
  }
  const target = getCompanyOverviewMetricTarget(key);
  if (target.type === 'declarations') {
    emit('openDeclarations');
    return;
  }
  emit('selectSection', { section: target.section });
}
function openRisk(code: string) {
  const target = getEnterpriseActionTarget(code);
  if (!target) return;
  if (target.type === 'declarations') {
    emit('openDeclarations', target.declarationId);
    return;
  }
  emit('selectSection', { section: target.section, tab: target.tab });
}
function formatMissingFields(fields: string[]) { return fields.map((field) => missingFieldLabels[field] ?? '信息待完善').join('、') || '资料完整'; }
async function refresh() { loading.value = true; errorMessage.value = ''; try { summary.value = await getEnterpriseWorkspaceSummaryApi(props.enterprise.id); } catch (error) { summary.value = undefined; errorMessage.value = error instanceof Error ? error.message : '企业资料概览加载失败'; } finally { loading.value = false; } }
watch(() => props.enterprise.id, () => void refresh(), { immediate: true });
</script>
<template><Spin :spinning="loading"><div class="enterprise-material-company-overview">
  <Alert v-if="errorMessage" :message="errorMessage" show-icon type="warning" />
  <section class="enterprise-material-company-overview__hero"><div><div class="enterprise-material-company-overview__eyebrow">企业资料总览</div><div class="enterprise-material-company-overview__title-row"><h3>{{ profile.name }}</h3><Tag :color="companyStatus.color">{{ companyStatus.label }}</Tag><Tag :color="profileStatus.color">{{ profileStatus.label }}</Tag></div><p>{{ profile.creditCode || '统一社会信用代码待补充' }}</p></div><Button aria-label="刷新企业资料概览" @click="refresh"><RotateCw class="size-4" />刷新</Button></section>
  <section class="enterprise-material-company-overview__metrics"><button type="button" @click="openMetric('health')"><span>企业资料健康分</span><strong>{{ metrics.healthScore }}</strong><Progress :percent="metrics.healthScore" :show-info="false" size="small" /></button><button type="button" @click="openMetric('completeness')"><span>资料完整率</span><strong>{{ metrics.completenessRate }}%</strong><p>{{ completionLabel }}</p></button><button type="button" @click="openMetric('attachments')"><span>资料沉淀</span><strong>{{ metrics.attachmentRecords }}</strong><p>份已归档附件记录</p></button><button type="button" @click="openMetric('declarations')"><span>进行中申报</span><strong>{{ metrics.activeDeclarations }}</strong><p>可在企业申报管理继续处理</p></button></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>高企关键指标</h4><p>企业资料中已沉淀的财税、人员与研发创新数据。</p></div></div><div class="enterprise-material-company-overview__indicators"><button v-for="item in indicatorItems" :key="item.label" type="button" @click="emit('selectSection', item.target)"><span>{{ item.label }}</span><strong>{{ item.value }}</strong></button></div></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>优先补齐</h4><p>按资料完整度排序，优先处理影响企业资料健康分的缺口。</p></div></div><div v-if="completionActions.length" class="enterprise-material-company-overview__completion-actions"><button v-for="item in completionActions" :key="`${item.moduleKey}-${item.tabKey}`" type="button" @click="selectMaterialItem(item.moduleKey, item.tabKey)"><div><strong>{{ item.itemName }}</strong><span>{{ formatMissingFields(item.missingFields) }}</span></div><div><Tag color="warning">{{ item.score }} 分</Tag><IconifyIcon icon="lucide:arrow-right" class="size-4" /></div></button></div><Empty v-else :image="Empty.PRESENTED_IMAGE_SIMPLE" description="当前企业资料已无待补齐子项" /></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>财税趋势</h4><p>近三年销售收入、研发费用和高新收入。</p></div><Button size="small" @click="selectSection('finance')">维护财税</Button></div><div v-if="summary?.financeTrend.length" class="enterprise-material-company-overview__trend"><button v-for="(row, index) in summary.financeTrend" :key="row.year || index" type="button" @click="selectSection('finance')"><strong>{{ row.year }}</strong><span>销售收入 {{ row.xxsr || '-' }}</span><span>研发费用 {{ row.rdExpense || '-' }}</span><span>高新收入 {{ row.highTechIncome || '-' }}</span></button></div><Empty v-else :image="Empty.PRESENTED_IMAGE_SIMPLE" description="暂无财税趋势数据" /></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>资料模块</h4><p>按客户端企业资料目录维护当前企业全部材料。</p></div></div><div class="enterprise-material-company-overview__modules"><button v-for="section in materialSections.filter((item) => item.key !== 'company')" :key="section.key" type="button" @click="selectSection(section.key)"><IconifyIcon :icon="section.icon" class="size-5" /><span>{{ section.title }}</span><IconifyIcon icon="lucide:arrow-up-right" class="enterprise-material-company-overview__module-arrow" /></button></div></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>资料模块进度</h4><p>统计每个资料子项的记录、附件与完整度，优先补齐未完成项。</p></div></div><div v-if="moduleStats.length" class="enterprise-material-company-overview__module-stats"><button v-for="item in moduleStats" :key="`${item.moduleKey}-${item.tabKey}`" type="button" @click="selectMaterialItem(item.moduleKey, item.tabKey)"><div><strong>{{ item.itemName }}</strong><span>{{ item.moduleName }}</span></div><div class="enterprise-material-company-overview__module-stat-values"><span>{{ item.recordCount }} 条资料</span><span>{{ item.attachmentCount }} 份附件</span><b :class="{ 'enterprise-material-company-overview__module-score--complete': item.isCompleted }">{{ item.score }} 分</b></div><p :class="{ 'enterprise-material-company-overview__module-missing--complete': item.isCompleted }">{{ formatMissingFields(item.missingFields) }}</p></button></div><Empty v-else :image="Empty.PRESENTED_IMAGE_SIMPLE" description="暂无资料模块统计" /></section>
  <section class="enterprise-material-company-overview__grid"><div class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>待处理风险</h4><p>根据资料完整度、申报状态和证据链自动汇总。</p></div></div><div v-if="summary?.risks.length" class="enterprise-material-company-overview__risks"><Alert v-for="risk in summary.risks" :key="risk.code" :description="risk.description" :message="risk.title" :type="getRiskType(risk.level)" show-icon><template v-if="getEnterpriseActionTarget(risk.code)" #action><Button size="small" type="link" @click="openRisk(risk.code)">处理</Button></template></Alert></div><Empty v-else :image="Empty.PRESENTED_IMAGE_SIMPLE" description="当前未发现待处理风险" /></div><div class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>近期申报</h4><p>项目进度及缺失材料概览。</p></div><Button size="small" @click="emit('openDeclarations')">查看申报</Button></div><div v-if="summary?.declarations.length" class="enterprise-material-company-overview__declarations"><button v-for="declaration in summary.declarations" :key="declaration.id" type="button" @click="emit('openDeclarations', declaration.id)"><div><strong>{{ declaration.projectName }}</strong><span>{{ declaration.currentNodeName || '待进入流程节点' }}</span></div><div class="enterprise-material-company-overview__declaration-meta"><Tag>{{ getDeclarationStatus(declaration.status) }}</Tag><span>{{ declaration.missingMaterialCount }} 项待补材料</span><span>{{ formatDate(declaration.deadline) }}</span></div></button></div><Empty v-else :image="Empty.PRESENTED_IMAGE_SIMPLE" description="暂无申报记录" /></div></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>最近操作</h4><p>记录当前企业资料维护、导入与申报处理结果。</p></div></div><EnterpriseOperationList :operations="summary?.recentOperations ?? []" /></section>
  <section class="enterprise-material-company-overview__section"><div class="enterprise-material-company-overview__section-heading"><div><h4>基础资料预览</h4><p>企业资料的基本信息与联系人字段。</p></div><Button size="small" type="primary" @click="selectSection('basic')">维护基础信息</Button></div><Descriptions bordered :column="{ lg: 2, md: 2, sm: 1, xs: 1 }" size="small"><DescriptionsItem v-for="item in profileItems" :key="item.label" :label="item.label">{{ item.value }}</DescriptionsItem></Descriptions></section>
</div></Spin></template>
<style scoped>
.enterprise-material-company-overview__completion-actions { display: grid; gap: 9px; }
.enterprise-material-company-overview__completion-actions button { display: flex; align-items: center; justify-content: space-between; gap: 12px; padding: 12px; color: #334155; text-align: left; cursor: pointer; background: #fffbeb; border: 1px solid #fde68a; border-radius: 4px; }
.enterprise-material-company-overview__completion-actions button:hover { border-color: #f59e0b; background: #fef3c7; }
.enterprise-material-company-overview__completion-actions button > div:first-child { display: grid; gap: 4px; min-width: 0; }
.enterprise-material-company-overview__completion-actions button span { overflow: hidden; color: #92400e; font-size: 12px; text-overflow: ellipsis; white-space: nowrap; }
.enterprise-material-company-overview__completion-actions button > div:last-child { display: flex; flex-shrink: 0; align-items: center; gap: 8px; }
.enterprise-material-company-overview__module-stats { display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 10px; }
.enterprise-material-company-overview__module-stats button { display: grid; gap: 8px; padding: 12px; color: #334155; text-align: left; cursor: pointer; background: #fff; border: 1px solid #e5e7eb; border-radius: 4px; }
.enterprise-material-company-overview__module-stats button:hover { border-color: #7dd3fc; background: #f0f9ff; }
.enterprise-material-company-overview__module-stats strong,.enterprise-material-company-overview__module-stats span { display: block; }
.enterprise-material-company-overview__module-stats > button > div:first-child span,.enterprise-material-company-overview__module-stat-values span { color: #6b7280; font-size: 12px; }
.enterprise-material-company-overview__module-stat-values { display: flex; flex-wrap: wrap; gap: 7px; align-items: center; }
.enterprise-material-company-overview__module-stat-values b { color: #b45309; font-size: 13px; }
.enterprise-material-company-overview__module-score--complete { color: #047857 !important; }
.enterprise-material-company-overview__module-stats p { margin: 0; color: #b45309; font-size: 12px; }
.enterprise-material-company-overview__module-missing--complete { color: #047857 !important; }
@media (max-width: 1080px) { .enterprise-material-company-overview__module-stats { grid-template-columns: repeat(2, minmax(0, 1fr)); } }
@media (max-width: 720px) { .enterprise-material-company-overview__module-stats { grid-template-columns: 1fr; } }
</style>
<style scoped>
.enterprise-material-company-overview__metrics button { display: grid; gap: 7px; min-width: 0; padding: 16px; text-align: left; cursor: pointer; border: 1px solid #e5e7eb; background: #fff; }
.enterprise-material-company-overview__metrics button:hover { border-color: #7dd3fc; background: #f0f9ff; }
</style>
<style scoped>.enterprise-material-company-overview { display: grid; gap: 16px; }.enterprise-material-company-overview__hero,.enterprise-material-company-overview__section,.enterprise-material-company-overview__metrics article { border: 1px solid #e5e7eb; background: #fff; }.enterprise-material-company-overview__hero { display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; padding: 20px; }.enterprise-material-company-overview__eyebrow,.enterprise-material-company-overview__hero p,.enterprise-material-company-overview__section-heading p,.enterprise-material-company-overview__metrics p { margin: 0; color: #6b7280; font-size: 13px; }.enterprise-material-company-overview__eyebrow { margin-bottom: 6px; }.enterprise-material-company-overview__title-row { display: flex; flex-wrap: wrap; align-items: center; gap: 8px; }.enterprise-material-company-overview__title-row h3,.enterprise-material-company-overview__section-heading h4 { margin: 0; letter-spacing: 0; color: #1f2937; }.enterprise-material-company-overview__title-row h3 { font-size: 22px; }.enterprise-material-company-overview__hero p { margin-top: 8px; }.enterprise-material-company-overview__metrics { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 12px; }.enterprise-material-company-overview__metrics article { display: grid; gap: 7px; min-width: 0; padding: 16px; }.enterprise-material-company-overview__metrics span,.enterprise-material-company-overview__indicators span { color: #6b7280; font-size: 13px; }.enterprise-material-company-overview__metrics strong { color: #0f172a; font-size: 28px; line-height: 1.1; }.enterprise-material-company-overview__section { padding: 18px; }.enterprise-material-company-overview__section-heading { display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; margin-bottom: 14px; }.enterprise-material-company-overview__section-heading p { margin-top: 5px; }.enterprise-material-company-overview__modules,.enterprise-