terial-company-overview__trend span,.enterprise-material-company-overview__recent-materials span { color: #6b7280; font-size: 12px; }.enterprise-material-company-overview__recent-materials button { justify-content: space-between; padding: 12px; }.enterprise-material-company-overview__recent-materials button > div:first-child { display: grid; gap: 4px; }.enterprise-material-company-overview__recent-materials button > div:last-child { display: flex; flex-wrap: wrap; gap: 6px; justify-content: flex-end; }.enterprise-material-company-overview__declarations button { justify-content: space-between; padding: 12px; }.enterprise-material-company-overview__declarations strong,.enterprise-material-company-overview__declarations span { display: block; }.enterprise-material-company-overview__declarations strong { color: #334155; }.enterprise-material-company-overview__declarations > button > div:first-child span,.enterprise-material-company-overview__declaration-meta span { margin-top: 4px; color: #6b7280; font-size: 12px; }.enterprise-material-company-overview__declaration-meta { display: flex; flex-wrap: wrap; justify-content: flex-end; gap: 6px; text-align: right; }@media (max-width: 1080px) {.enterprise-material-company-overview__metrics { grid-template-columns: repeat(2, minmax(0, 1fr)); }.enterprise-material-company-overview__modules,.enterprise-material-company-overview__indicators { grid-template-columns: repeat(2, minmax(0, 1fr)); }.enterprise-material-company-overview__trend { grid-template-columns: 1fr; }}@media (max-width: 720px) {.enterprise-material-company-overview__hero,.enterprise-material-company-overview__section-heading,.enterprise-material-company-overview__declarations button,.enterprise-material-company-overview__recent-materials button { flex-direction: column; }.enterprise-material-company-overview__metrics,.enterprise-material-company-overview__modules,.enterprise-material-company-overview__indicators,.enterprise-material-company-overview__grid { grid-template-columns: 1fr; }.enterprise-material-company-overview__declaration-meta,.enterprise-material-company-overview__recent-materials button > div:last-child { justify-content: flex-start; text-align: left; }}</style>
